DATA_DICTIONARY_MD = '# Data folder\n\nThis folder contains anonymized and synthetic CSV data for the Remote ERP Onboarding Workflow Case Study.\n\n## Files\n\n- `synthetic_onboarding_event_log.csv`  \n  Reconstructed and anonymized event-level timeline of onboarding artifacts and activities.\n\n- `artifact_inventory.csv`  \n  Anonymized inventory of artifact categories observed during the case.\n\n- `onboarding_failure_taxonomy.csv`  \n  Failure taxonomy for remote ERP onboarding and knowledge-transfer breakdown.\n\n- `role_expectation_matrix.csv`  \n  Role modes and expectation risks observed in the onboarding structure.\n\n- `knowledge_transfer_gap_matrix.csv`  \n  Knowledge areas, prerequisites, observed artifacts, gap types, and recommended scaffolds.\n\n## Important\n\nThese files do not contain raw customer documents, passwords, credentials, personal information, original meeting recordings, or confidential project files.\n\nThe data is reconstructed, anonymized, and summarized for research, portfolio, and CWI demonstration purposes.\n'


def write_files() -> None:
    for filename, content in CSV_FILES.items():
        output_path = DATA_DIR / filename
        output_path.write_text(content, encoding="utf-8")
        print(f"Wrote {output_path}")

    dictionary_path = DOCS_DIR / "data_dictionary.md"
    dictionary_path.write_text(DATA_DICTIONARY_MD, encoding="utf-8")
    print(f"Wrote {dictionary_path}")


if __name__ == "__main__":
    write_files()
